'use client'

import { useEffect, useState } from 'react'
import { useRouter } from 'next/navigation'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/lib/auth-context'
import AdminSidebar from '@/components/admin/AdminSidebar'
import { Plus, Search, Loader2, Edit2, Trash2, Check, X } from 'lucide-react'
import { toast } from '@/lib/toast'

interface Category {
  id: string;
  name: string;
  slug: string;
  image_url: string;
  description: string;
  sort_order: number;
  is_active: boolean;
}

export default function AdminCategoriesPage() {
  const router = useRouter()
  const { profile, loading: authLoading } = useAuth()
  const [categories, setCategories] = useState<Category[]>([])
  const [loading, setLoading] = useState(true)
  const [search, setSearch] = useState('')
  const [editingId, setEditingId] = useState<string | null>(null)
  const [formData, setFormData] = useState<Partial<Category>>({})
  const [isAdding, setIsAdding] = useState(false)
  const [uploading, setUploading] = useState(false)

  useEffect(() => {
    if (!authLoading && !profile?.is_admin) {
      router.push('/admin/login')
    }
  }, [profile, authLoading, router])

  useEffect(() => {
    if (profile?.is_admin) fetchCategories()
  }, [profile])

  async function fetchCategories() {
    setLoading(true)
    const { data } = await supabase.from('categories').select('*').order('sort_order')
    setCategories(data || [])
    setLoading(false)
  }

  const handleEdit = (cat: Category) => {
    setEditingId(cat.id)
    setFormData(cat)
    setIsAdding(false)
  }

  const handleSave = async () => {
    if (!formData.name || !formData.slug) {
      toast.error('Name and slug are required')
      return
    }

    const payload = {
      name: formData.name,
      slug: formData.slug,
      image_url: formData.image_url || '',
      description: formData.description || '',
      sort_order: formData.sort_order || 0,
      is_active: formData.is_active ?? true
    }

    const { error } = editingId 
      ? await supabase.from('categories').update(payload).eq('id', editingId)
      : await supabase.from('categories').insert(payload)

    if (error) {
      toast.error(error.message)
    } else {
      toast.success(`Category ${editingId ? 'updated' : 'added'} successfully`)
      setEditingId(null)
      setIsAdding(false)
      fetchCategories()
    }
  }

  const handleUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    try {
      const file = e.target.files?.[0]
      if (!file) return

      setUploading(true)
      const fileExt = file.name.split('.').pop()
      const fileName = `${Math.random()}.${fileExt}`
      const filePath = `categories/${fileName}`

      const { error: uploadError } = await supabase.storage
        .from('products') // Using products bucket for categories too, or I can add a categories bucket in SQL
        .upload(filePath, file)

      if (uploadError) throw uploadError

      const { data: { publicUrl } } = supabase.storage
        .from('products')
        .getPublicUrl(filePath)

      setFormData({ ...formData, image_url: publicUrl })
      toast.success('Category image uploaded')
    } catch (error: any) {
      toast.error(error.message || 'Error uploading')
    } finally {
      setUploading(false)
    }
  }

  const handleDelete = async (id: string) => {
    if (!confirm('Are you sure you want to delete this category?')) return
    const { error } = await supabase.from('categories').delete().eq('id', id)
    if (error) toast.error(error.message)
    else {
      toast.success('Category deleted')
      fetchCategories()
    }
  }

  const filtered = categories.filter(c => (c.name || '').toLowerCase().includes(search.toLowerCase()))

  if (authLoading || (loading && categories.length === 0)) {
    return (
      <div style={{ display: 'flex', minHeight: '100vh', alignItems: 'center', justifyContent: 'center', background: 'var(--bg-primary)' }}>
        <Loader2 size={32} className="animate-spin" style={{ color: 'var(--gold)' }} />
      </div>
    )
  }

  if (!profile?.is_admin) return null

  return (
    <div style={{ display: 'flex', minHeight: '100vh', background: 'var(--bg-primary)' }}>
      <AdminSidebar active="categories" />

      <div style={{ flex: 1, padding: 32, overflow: 'auto' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 32 }}>
          <h1 style={{ fontFamily: 'var(--font-heading)', fontSize: 28, fontWeight: 800 }}>Categories</h1>
          <button className="btn btn-primary" onClick={() => { setIsAdding(true); setEditingId(null); setFormData({ is_active: true, sort_order: 0 }) }}>
            <Plus size={18} /> Add Category
          </button>
        </div>

        {/* List & Form Grid */}
        <div style={{ display: 'grid', gridTemplateColumns: (editingId || isAdding) ? '1fr 380px' : '1fr', gap: 24, alignItems: 'start' }}>

          <div className="card" style={{ padding: 0, overflow: 'hidden' }}>
            <div style={{ padding: 16, borderBottom: '1px solid var(--border)', display: 'flex', gap: 12 }}>
               <div style={{ position: 'relative', flex: 1 }}>
                 <Search size={16} style={{ position: 'absolute', left: 12, top: '50%', transform: 'translateY(-50%)', color: 'var(--text-muted)' }} />
                 <input value={search} onChange={e => setSearch(e.target.value)} className="form-input" placeholder="Search categories..." style={{ paddingLeft: 36, height: 40 }} />
               </div>
            </div>

            {loading ? (
              <div style={{ padding: 40, textAlign: 'center' }}><Loader2 size={24} className="animate-spin" style={{ color: 'var(--gold)' }} /></div>
            ) : (
              <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 14 }}>
                <thead>
                  <tr style={{ background: '#fafafa', borderBottom: '1px solid var(--border)' }}>
                    <th style={{ padding: '12px 16px', textAlign: 'left', fontWeight: 700, fontSize: 11, textTransform: 'uppercase', color: 'var(--text-muted)' }}>Name</th>
                    <th style={{ padding: '12px 16px', textAlign: 'left', fontWeight: 700, fontSize: 11, textTransform: 'uppercase', color: 'var(--text-muted)' }}>Slug</th>
                    <th style={{ padding: '12px 16px', textAlign: 'center', fontWeight: 700, fontSize: 11, textTransform: 'uppercase', color: 'var(--text-muted)' }}>Order</th>
                    <th style={{ padding: '12px 16px', textAlign: 'center', fontWeight: 700, fontSize: 11, textTransform: 'uppercase', color: 'var(--text-muted)' }}>Status</th>
                    <th style={{ padding: '12px 16px', textAlign: 'right', fontWeight: 700, fontSize: 11, textTransform: 'uppercase', color: 'var(--text-muted)' }}>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {filtered.map(cat => (
                    <tr key={cat.id} style={{ borderBottom: '1px solid var(--border)', background: editingId === cat.id ? '#fff9f0' : 'transparent' }}>
                      <td style={{ padding: '12px 16px', fontWeight: 600 }}>{cat.name || 'Unnamed Category'}</td>
                      <td style={{ padding: '12px 16px', color: 'var(--text-muted)' }}>{cat.slug}</td>
                      <td style={{ padding: '12px 16px', textAlign: 'center' }}>{cat.sort_order}</td>
                      <td style={{ padding: '12px 16px', textAlign: 'center' }}>
                        <span style={{ padding: '2px 8px', borderRadius: 4, fontSize: 11, fontWeight: 700, background: cat.is_active ? '#dcfce7' : '#fee2e2', color: cat.is_active ? '#166534' : '#991b1b' }}>
                          {cat.is_active ? 'Active' : 'Inactive'}
                        </span>
                      </td>
                      <td style={{ padding: '12px 16px', textAlign: 'right' }}>
                        <div style={{ display: 'flex', gap: 8, justifyContent: 'flex-end' }}>
                          <button onClick={() => handleEdit(cat)} style={{ padding: 6, background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-muted)' }}><Edit2 size={16} /></button>
                          <button onClick={() => handleDelete(cat.id)} style={{ padding: 6, background: 'none', border: 'none', cursor: 'pointer', color: '#ef4444' }}><Trash2 size={16} /></button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>

          {(editingId || isAdding) && (
            <div className="card" style={{ padding: 24, position: 'sticky', top: 32 }}>
              <h2 className="heading-md" style={{ marginBottom: 20 }}>{editingId ? 'Edit Category' : 'New Category'}</h2>

              <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
                <div className="form-group">
                  <label className="form-label">Name</label>
                  <input className="form-input" value={formData.name || ''} onChange={e => setFormData({ ...formData, name: e.target.value })} placeholder="e.g. Men Wear" />
                </div>
                <div className="form-group">
                  <label className="form-label">Slug</label>
                  <input className="form-input" value={formData.slug || ''} onChange={e => setFormData({ ...formData, slug: e.target.value.toLowerCase().replace(/\s+/g, '-') })} placeholder="e.g. men-wear" />
                </div>
                <div className="form-group">
                  <label className="form-label" style={{ display: 'flex', justifyContent: 'space-between' }}>
                    Image
                    <label style={{ color: 'var(--gold)', cursor: 'pointer', fontSize: 12, fontWeight: 600 }}>
                      {uploading ? 'Uploading...' : 'Upload Image'}
                      <input type="file" accept="image/*" onChange={handleUpload} disabled={uploading} style={{ display: 'none' }} />
                    </label>
                  </label>
                  <input className="form-input" value={formData.image_url || ''} onChange={e => setFormData({ ...formData, image_url: e.target.value })} placeholder="https://..." />
                </div>
                <div className="form-group">
                  <label className="form-label">Sort Order</label>
                  <input type="number" className="form-input" value={formData.sort_order || 0} onChange={e => setFormData({ ...formData, sort_order: parseInt(e.target.value) })} />
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                  <input type="checkbox" id="cat-active" checked={formData.is_active ?? true} onChange={e => setFormData({ ...formData, is_active: e.target.checked })} />
                  <label htmlFor="cat-active" style={{ fontSize: 14 }}>Active</label>
                </div>

                <div style={{ display: 'flex', gap: 10, marginTop: 12 }}>
                  <button className="btn btn-primary" style={{ flex: 1 }} onClick={handleSave}>
                    <Check size={18} /> Save
                  </button>
                  <button className="btn btn-outline" onClick={() => { setIsAdding(false); setEditingId(null) }}>
                    <X size={18} />
                  </button>
                </div>
              </div>
            </div>
          )}

        </div>
      </div>
    </div>
  )
}

'use client'

import { useState } from 'react'
import { supabase } from '@/lib/supabase'
import { useRouter } from 'next/navigation'
import { toast } from '@/lib/toast'
import { Loader2, Eye, EyeOff, AlertCircle } from 'lucide-react'

// Admin credentials: hakeemrazq@gmail.com / asad123
// Note: Create this user via Supabase Dashboard > Auth > Add User, then run:
// UPDATE profiles SET is_admin = TRUE WHERE id = '<user-uuid>';

export default function AdminLoginPage() {
  const router = useRouter()
  const [form, setForm] = useState({ email: '', password: '' })
  const [loading, setLoading] = useState(false)
  const [showPw, setShowPw] = useState(false)
  const [error, setError] = useState('')

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault()
    setError('')
    setLoading(true)

    try {
      const { data, error: authError } = await supabase.auth.signInWithPassword({ 
        email: form.email, 
        password: form.password 
      })

      if (authError || !data?.user) { 
        setError(authError?.message || 'Invalid credentials'); 
        setLoading(false); 
        return 
      }

      // Verify admin status
      let { data: profileData, error: profileError } = await supabase
        .from('profiles')
        .select('is_admin')
        .eq('id', data.user.id)
        .single()

      // SELF-HEALING: If profile is missing but user is master email, create it
      if (profileError && profileError.code === 'PGRST116' && form.email === 'hakeemrazq@gmail.com') {
        console.log('Master admin profile missing. Healing...')
        const { data: newProfile, error: createError } = await supabase
          .from('profiles')
          .insert({
            id: data.user.id,
            full_name: 'Master Admin',
            is_admin: true
          })
          .select('is_admin')
          .single()

        if (!createError) {
          profileData = newProfile
          profileError = null
        }
      }

      if (profileError) {
        console.error('Detailed Profile Error:', {
          code: profileError.code,
          message: profileError.message,
          details: profileError.details
        })
        await supabase.auth.signOut()
        setError(`Database Error (${profileError.code}): Your profile record could not be found. Please contact support.`)
        setLoading(false)
        return
      }

      if (!profileData?.is_admin) {
        await supabase.auth.signOut()
        setError('Access denied. This account does not have admin privileges.')
        setLoading(false)
        return
      }

      toast.success('Welcome to Admin Panel')
      router.push('/admin')
    } catch (err) {
      setError('A connection error occurred. Please try again.')
    } finally {
      setLoading(false)
    }
  }

  return (
    <div style={{ minHeight: '100vh', display: 'flex', background: '#050505' }}>
      {/* Left Panel - Brand Story */}
      <div style={{ flex: 1, position: 'relative', overflow: 'hidden', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', padding: 60 }} className="admin-login-left">
        <div style={{ position: 'absolute', inset: 0, background: 'radial-gradient(circle at 30% 30%, rgba(201,166,107,0.15) 0%, transparent 50%), radial-gradient(circle at 70% 70%, rgba(201,166,107,0.08) 0%, transparent 50%)', zIndex: 0 }} />

        <div style={{ position: 'relative', zIndex: 1, textAlign: 'center', maxWidth: 440 }}>
          <h2 style={{ fontFamily: 'var(--font-heading)', fontSize: 56, fontWeight: 800, letterSpacing: '0.05em', color: '#fff', textTransform: 'uppercase', marginBottom: 8 }}>Aurangzaib</h2>
          <div style={{ color: 'var(--gold)', fontSize: 16, letterSpacing: '0.4em', textTransform: 'uppercase', fontWeight: 600 }}>Master Dashboard</div>
          <div style={{ width: 60, height: 2, background: 'var(--gold)', margin: '40px auto' }} />
          <p style={{ color: 'rgba(255,255,255,0.4)', fontSize: 18, lineHeight: 1.6, fontWeight: 300, fontStyle: 'italic' }}>
            "Where heritage meets modern management."
          </p>
        </div>
      </div>

      {/* Login Form Panel */}
      <div style={{ width: '100%', maxWidth: 540, background: '#0a0a0a', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 40, borderLeft: '1px solid rgba(255,255,255,0.05)' }}>
        <div style={{ width: '100%', maxWidth: 400 }}>
          <div style={{ marginBottom: 48 }}>
            <h1 style={{ color: '#fff', fontFamily: 'var(--font-heading)', fontSize: 32, fontWeight: 700, marginBottom: 8 }}>Admin Login</h1>
            <p style={{ color: 'rgba(255,255,255,0.5)', fontSize: 14 }}>Enter your credentials to access the command center.</p>
          </div>

          {error && (
            <div style={{ background: 'rgba(239,68,68,0.1)', border: '1px solid rgba(239,68,68,0.2)', borderRadius: 8, padding: '16px', color: '#fca5a5', fontSize: 14, marginBottom: 32, animation: 'fadeIn 0.3s ease' }}>
              <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
                <AlertCircle size={18} />
                {error}
              </div>
            </div>
          )}

          <form onSubmit={handleLogin} style={{ display: 'flex', flexDirection: 'column', gap: 24 }}>
            <div className="form-group">
              <label className="form-label" style={{ color: 'rgba(255,255,255,0.6)', fontSize: 12 }}>Corporate Email</label>
              <input 
                type="email" 
                className="form-input" 
                value={form.email} 
                onChange={e => setForm(f => ({ ...f, email: e.target.value }))} 
                placeholder="admin@aurangzaib.com" 
                required 
                style={{ background: '#111', color: '#fff', borderColor: 'rgba(255,255,255,0.1)', height: 52 }} 
              />
            </div>

            <div className="form-group">
              <label className="form-label" style={{ color: 'rgba(255,255,255,0.6)', fontSize: 12 }}>Security Password</label>
              <div style={{ position: 'relative' }}>
                <input 
                  type={showPw ? 'text' : 'password'} 
                  className="form-input" 
                  value={form.password} 
                  onChange={e => setForm(f => ({ ...f, password: e.target.value }))} 
                  placeholder="••••••••" 
                  required 
                  style={{ background: '#111', color: '#fff', borderColor: 'rgba(255,255,255,0.1)', height: 52 }} 
                />
                <button 
                  type="button" 
                  onClick={() => setShowPw(!showPw)} 
                  style={{ position: 'absolute', right: 16, top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', cursor: 'pointer', color: 'rgba(255,255,255,0.4)' }}
                >
                  {showPw ? <EyeOff size={20} /> : <Eye size={20} />}
                </button>
              </div>
            </div>

            <button 
              type="submit" 
              className="btn btn-gold" 
              disabled={loading} 
              style={{ height: 52, marginTop: 12, borderRadius: 8, fontSize: 15, fontWeight: 700 }}
            >
              {loading ? (
                <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                  <Loader2 size={20} className="animate-spin" /> Verifying...
                </div>
              ) : 'Authenticate Access'}
            </button>
          </form>

          <div style={{ marginTop: 40, textAlign: 'center' }}>
            <div style={{ fontSize: 12, color: 'rgba(255,255,255,0.3)', letterSpacing: '0.05em' }}>
              &copy; 2026 Aurangzaib Garments Private Limited.
            </div>
          </div>
        </div>
      </div>

      <style jsx>{`
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .animate-spin { animation: spin 1s linear infinite; }
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        @media (max-width: 900px) {
          .admin-login-left { display: none !important; }
        }
      `}</style>
    </div>
  )
}

'use client'

import { useEffect, useState } from 'react'
import { useAuth } from '@/lib/auth-context'
import { supabase } from '@/lib/supabase'
import AdminSidebar from '@/components/admin/AdminSidebar'
import { Search, Filter, Loader2, ChevronDown, Eye } from 'lucide-react'
import { toast } from '@/lib/toast'

interface Order {
  id: string; order_number: string; customer_name: string; customer_phone: string;
  customer_city: string; total: number; status: string; payment_method: string;
  created_at: string; items: Array<{ product_name: string; quantity: number; price: number; size?: string }>
}

const STATUSES = ['pending', 'approved', 'processing', 'shipping', 'out_for_delivery', 'delivered', 'cancelled']
const STATUS_COLORS: Record<string, string> = {
  pending: '#f59e0b', approved: '#3b82f6', processing: '#8b5cf6',
  shipping: '#06b6d4', out_for_delivery: '#f97316', delivered: '#22c55e', cancelled: '#ef4444'
}

export default function AdminOrdersPage() {
  const { profile } = useAuth()
  const [orders, setOrders] = useState<Order[]>([])
  const [fetching, setFetching] = useState(true)
  const [search, setSearch] = useState('')
  const [statusFilter, setStatusFilter] = useState('')
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null)
  const [updatingStatus, setUpdatingStatus] = useState(false)

  useEffect(() => { if (profile?.is_admin) fetchOrders() }, [profile, statusFilter])

  async function fetchOrders() {
    setFetching(true)
    let q = supabase.from('orders').select('*').order('created_at', { ascending: false })
    if (statusFilter) q = q.eq('status', statusFilter)
    const { data } = await q
    setOrders(data || [])
    setFetching(false)
  }

  const handleStatusChange = async (orderId: string, newStatus: string) => {
    setUpdatingStatus(true)
    const order = orders.find(o => o.id === orderId)
    if (!order) return
    const statusHistory = [
      { status: newStatus, timestamp: new Date().toISOString(), note: `Status changed to ${newStatus}` }
    ]
    const { error } = await supabase.from('orders').update({ status: newStatus, status_history: statusHistory }).eq('id', orderId)
    setUpdatingStatus(false)
    if (error) toast.error(error.message)
    else {
      toast.success(`Order updated to ${newStatus}`)
      setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status: newStatus } : o))
      if (selectedOrder?.id === orderId) setSelectedOrder(prev => prev ? { ...prev, status: newStatus } : null)
    }
  }

  const filtered = orders.filter(o =>
    o.order_number.toLowerCase().includes(search.toLowerCase()) ||
    o.customer_name.toLowerCase().includes(search.toLowerCase()) ||
    o.customer_phone.includes(search)
  )

  if (!profile?.is_admin) return null

  return (
    <div style={{ display: 'flex', minHeight: '100vh', background: 'var(--bg-primary)' }}>
      <AdminSidebar active="orders" />

      <div style={{ flex: 1, padding: 32, overflow: 'auto' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 32 }}>
          <h1 style={{ fontFamily: 'var(--font-heading)', fontSize: 28, fontWeight: 800 }}>Orders</h1>
          <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
            <span style={{ fontSize: 13, color: 'var(--text-muted)' }}>{orders.length} orders</span>
          </div>
        </div>

        {/* Filters */}
        <div style={{ display: 'flex', gap: 12, marginBottom: 24, flexWrap: 'wrap' }}>
          <div style={{ position: 'relative', flex: 1, minWidth: 200 }}>
            <Search size={16} style={{ position: 'absolute', left: 14, top: '50%', transform: 'translateY(-50%)', color: 'var(--text-muted)' }} />
            <input value={search} onChange={e => setSearch(e.target.value)} className="form-input" placeholder="Search order, customer, phone..." style={{ paddingLeft: 40 }} />
          </div>
          <div style={{ position: 'relative' }}>
            <Filter size={14} style={{ position: 'absolute', left: 12, top: '50%', transform: 'translateY(-50%)', color: 'var(--text-muted)', zIndex: 1 }} />
            <select value={statusFilter} onChange={e => setStatusFilter(e.target.value)} className="form-input" style={{ paddingLeft: 32 }}>
              <option value="">All Statuses</option>
              {STATUSES.map(s => <option key={s} value={s}>{s.replace(/_/g, ' ')}</option>)}
            </select>
          </div>
        </div>

        <div style={{ display: 'grid', gridTemplateColumns: selectedOrder ? '1fr 380px' : '1fr', gap: 24, alignItems: 'start' }}>
          {/* Orders Table */}
          <div className="card" style={{ overflow: 'hidden', padding: 0 }}>
            {fetching ? (
              <div style={{ padding: 40, textAlign: 'center' }}><Loader2 size={24} style={{ animation: 'spin 1s linear infinite', color: 'var(--gold)' }} /></div>
            ) : (
              <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 14 }}>
                <thead>
                  <tr style={{ background: 'var(--bg-primary)' }}>
                    {['Order #', 'Customer', 'City', 'Total', 'Status', 'Date', ''].map((h, i) => (
                      <th key={i} style={{ padding: '10px 16px', textAlign: 'left', fontSize: 11, fontWeight: 700, letterSpacing: '0.08em', textTransform: 'uppercase', color: 'var(--text-muted)' }}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {filtered.map(order => (
                    <tr key={order.id} style={{ borderTop: '1px solid var(--border)', cursor: 'pointer', background: selectedOrder?.id === order.id ? 'var(--bg-secondary)' : 'transparent' }} onClick={() => setSelectedOrder(selectedOrder?.id === order.id ? null : order)}>
                      <td style={{ padding: '12px 16px', fontWeight: 700, fontFamily: 'var(--font-heading)', color: 'var(--dark)' }}>{order.order_number}</td>
                      <td style={{ padding: '12px 16px' }}>
                        <div style={{ fontWeight: 500 }}>{order.customer_name}</div>
                        <div style={{ fontSize: 11, color: 'var(--text-muted)' }}>{order.customer_phone}</div>
                      </td>
                      <td style={{ padding: '12px 16px', color: 'var(--text-secondary)' }}>{order.customer_city}</td>
                      <td style={{ padding: '12px 16px', fontWeight: 600 }}>Rs. {order.total.toLocaleString()}</td>
                      <td style={{ padding: '12px 16px' }}>
                        <span style={{ background: `${STATUS_COLORS[order.status]}20`, color: STATUS_COLORS[order.status], padding: '3px 8px', borderRadius: 4, fontSize: 11, fontWeight: 700, textTransform: 'capitalize' }}>
                          {order.status.replace(/_/g, ' ')}
                        </span>
                      </td>
                      <td style={{ padding: '12px 16px', color: 'var(--text-muted)', fontSize: 12 }}>{new Date(order.created_at).toLocaleDateString()}</td>
                      <td style={{ padding: '12px 16px' }}><Eye size={16} color="var(--text-muted)" /></td>
                    </tr>
                  ))}
                  {filtered.length === 0 && (
                    <tr><td colSpan={7} style={{ padding: 40, textAlign: 'center', color: 'var(--text-muted)' }}>No orders found</td></tr>
                  )}
                </tbody>
              </table>
            )}
          </div>

          {/* Order Detail Panel */}
          {selectedOrder && (
            <div className="card" style={{ padding: 24, position: 'sticky', top: 24 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 16 }}>
                <h3 style={{ fontFamily: 'var(--font-heading)', fontWeight: 700 }}>{selectedOrder.order_number}</h3>
                <button onClick={() => setSelectedOrder(null)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-muted)' }}>✕</button>
              </div>

              {/* Status Updater */}
              <div style={{ marginBottom: 20 }}>
                <label className="form-label">Update Status</label>
                <div style={{ position: 'relative' }}>
                  <select
                    value={selectedOrder.status}
                    onChange={e => handleStatusChange(selectedOrder.id, e.target.value)}
                    disabled={updatingStatus}
                    className="form-input"
                  >
                    {STATUSES.map(s => <option key={s} value={s}>{s.replace(/_/g, ' ')}</option>)}
                  </select>
                  <ChevronDown size={14} style={{ position: 'absolute', right: 12, top: '50%', transform: 'translateY(-50%)', pointerEvents: 'none', color: 'var(--text-muted)' }} />
                </div>
              </div>

              {/* Customer */}
              <div style={{ marginBottom: 16 }}>
                <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: '0.1em', textTransform: 'uppercase', color: 'var(--text-muted)', marginBottom: 8 }}>Customer</div>
                <div style={{ fontSize: 14, fontWeight: 600 }}>{selectedOrder.customer_name}</div>
                <div style={{ fontSize: 13, color: 'var(--text-muted)' }}>{selectedOrder.customer_phone}</div>
                <div style={{ fontSize: 13, color: 'var(--text-muted)' }}>{selectedOrder.customer_city}</div>
              </div>

              {/* Items */}
              <div style={{ marginBottom: 16 }}>
                <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: '0.1em', textTransform: 'uppercase', color: 'var(--text-muted)', marginBottom: 8 }}>Items</div>
                {selectedOrder.items?.map((item, i) => (
                  <div key={i} style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13, padding: '6px 0', borderBottom: '1px solid var(--border)' }}>
                    <span>{item.product_name} {item.size ? `(${item.size})` : ''} × {item.quantity}</span>
                    <span style={{ fontWeight: 600 }}>Rs. {(item.price * item.quantity).toLocaleString()}</span>
                  </div>
                ))}
                <div style={{ display: 'flex', justifyContent: 'space-between', fontWeight: 800, padding: '10px 0 0', fontFamily: 'var(--font-heading)' }}>
                  <span>Total</span>
                  <span>Rs. {selectedOrder.total.toLocaleString()}</span>
                </div>
              </div>

              <div style={{ display: 'flex', gap: 8 }}>
                <a href={`https://wa.me/92${selectedOrder.customer_phone.replace(/^0/, '')}`} target="_blank" rel="noopener noreferrer" className="btn btn-outline btn-sm" style={{ flex: 1, justifyContent: 'center' }}>
                  📱 WhatsApp
                </a>
                <a href={`/track-order?order=${selectedOrder.order_number}`} target="_blank" rel="noopener noreferrer" className="btn btn-outline btn-sm" style={{ flex: 1, justifyContent: 'center' }}>
                  Track Page
                </a>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

'use client'

import { useEffect, useState } from 'react'
import { useRouter } from 'next/navigation'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/lib/auth-context'
import AdminSidebar from '@/components/admin/AdminSidebar'
import { ShoppingBag, Users, Package, TrendingUp, ArrowUpRight, ArrowDownRight, Clock, CheckCircle, Truck, AlertCircle, Loader2 } from 'lucide-react'
import { toast } from '@/lib/toast'

interface Stats {
  totalOrders: number;
  totalRevenue: number;
  totalProducts: number;
  totalUsers: number;
  recentOrders: any[];
  statusCounts: { [key: string]: number };
}

export default function AdminDashboard() {
  const router = useRouter()
  const { profile, loading: authLoading } = useAuth()
  const [stats, setStats] = useState<Stats | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    if (!authLoading && !profile?.is_admin) {
      router.push('/admin/login')
    }
  }, [profile, authLoading, router])

  useEffect(() => {
    if (profile?.is_admin) fetchStats()
  }, [profile])

  async function fetchStats() {
    try {
      setLoading(true)

      const { data: orders } = await supabase.from('orders').select('*').order('created_at', { ascending: false })
      const { data: products } = await supabase.from('products').select('id')
      const { data: profiles } = await supabase.from('profiles').select('id').eq('is_admin', false)

      const revenue = orders?.reduce((acc, curr) => acc + (Number(curr.total) || 0), 0) || 0
      const statusCounts = orders?.reduce((acc: any, curr) => {
        acc[curr.status] = (acc[curr.status] || 0) + 1
        return acc
      }, {}) || {}

      setStats({
        totalOrders: orders?.length || 0,
        totalRevenue: revenue,
        totalProducts: products?.length || 0,
        totalUsers: profiles?.length || 0,
        recentOrders: orders?.slice(0, 5) || [],
        statusCounts
      })
    } catch (error: any) {
      toast.error('Failed to load dashboard stats')
    } finally {
      setLoading(false)
    }
  }

  if (authLoading || (loading && !stats)) {
    return (
      <div style={{ display: 'flex', minHeight: '100vh', alignItems: 'center', justifyContent: 'center', background: 'var(--bg-primary)' }}>
        <Loader2 size={32} style={{ animation: 'spin 1s linear infinite', color: 'var(--gold)' }} />
      </div>
    )
  }

  const CARDS = [
    { label: 'Total Revenue', value: `PKR ${(stats?.totalRevenue || 0).toLocaleString()}`, icon: TrendingUp, color: '#0ea5e9', trend: '+12.5%', isUp: true },
    { label: 'Total Orders', value: stats?.totalOrders || 0, icon: ShoppingBag, color: '#f59e0b', trend: '+8.2%', isUp: true },
    { label: 'Total Products', value: stats?.totalProducts || 0, icon: Package, color: '#10b981', trend: '-2.1%', isUp: false },
    { label: 'Active Users', value: stats?.totalUsers || 0, icon: Users, color: '#8b5cf6', trend: '+4.3%', isUp: true },
  ]

  return (
    <div style={{ display: 'flex', minHeight: '100vh', background: 'var(--bg-primary)' }}>
      <AdminSidebar active="dashboard" />

      <div style={{ flex: 1, padding: 32, overflow: 'auto' }}>
        <div style={{ marginBottom: 32 }}>
          <h1 style={{ fontFamily: 'var(--font-heading)', fontSize: 28, fontWeight: 800, color: 'var(--dark)' }}>Dashboard</h1>
          <p style={{ color: 'var(--text-muted)', fontSize: 14 }}>Welcome back, {profile?.full_name}. Here's what's happening today.</p>
        </div>

        {/* Stats Grid */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))', gap: 24, marginBottom: 32 }}>
          {CARDS.map((card, i) => {
            const Icon = card.icon
            return (
              <div key={i} className="card" style={{ padding: 24 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 16 }}>
                  <div style={{ width: 48, height: 48, borderRadius: 12, background: `${card.color}15`, display: 'flex', alignItems: 'center', justifyContent: 'center', color: card.color }}>
                    <Icon size={24} />
                  </div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 4, fontSize: 12, fontWeight: 600, color: card.isUp ? '#10b981' : '#ef4444' }}>
                    {card.trend} {card.isUp ? <ArrowUpRight size={14} /> : <ArrowDownRight size={14} />}
                  </div>
                </div>
                <div style={{ fontSize: 14, color: 'var(--text-muted)', fontWeight: 500, marginBottom: 4 }}>{card.label}</div>
                <div style={{ fontSize: 24, fontWeight: 800, color: 'var(--dark)' }}>{loading ? '...' : card.value}</div>
              </div>
            )
          })}
        </div>

        <div style={{ display: 'grid', gridTemplateColumns: '1.5fr 1fr', gap: 24 }}>
          {/* Recent Orders */}
          <div className="card" style={{ padding: 0 }}>
            <div style={{ padding: 24, borderBottom: '1px solid var(--border)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <h2 style={{ fontSize: 18, fontWeight: 700 }}>Recent Orders</h2>
              <button style={{ fontSize: 13, fontWeight: 600, color: 'var(--gold)', background: 'none', border: 'none', cursor: 'pointer' }}>View All</button>
            </div>
            <div style={{ overflowX: 'auto' }}>
              <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 14 }}>
                <thead>
                  <tr style={{ background: '#fafafa', borderBottom: '1px solid var(--border)' }}>
                    <th style={{ padding: '12px 24px', textAlign: 'left', fontSize: 11, fontWeight: 700, textTransform: 'uppercase', color: 'var(--text-muted)' }}>Order ID</th>
                    <th style={{ padding: '12px 24px', textAlign: 'left', fontSize: 11, fontWeight: 700, textTransform: 'uppercase', color: 'var(--text-muted)' }}>Customer</th>
                    <th style={{ padding: '12px 24px', textAlign: 'left', fontSize: 11, fontWeight: 700, textTransform: 'uppercase', color: 'var(--text-muted)' }}>Total</th>
                    <th style={{ padding: '12px 24px', textAlign: 'right', fontSize: 11, fontWeight: 700, textTransform: 'uppercase', color: 'var(--text-muted)' }}>Status</th>
                  </tr>
                </thead>
                <tbody>
                  {stats?.recentOrders.map(order => (
                    <tr key={order.id} style={{ borderBottom: '1px solid var(--border)' }}>
                      <td style={{ padding: '16px 24px', fontWeight: 600 }}>#{order.id.slice(0, 8)}</td>
                      <td style={{ padding: '16px 24px' }}>{order.customer_name}</td>
                      <td style={{ padding: '16px 24px' }}>PKR {Number(order.total || 0).toLocaleString()}</td>
                      <td style={{ padding: '16px 24px', textAlign: 'right' }}>
                        <span style={{ fontSize: 11, fontWeight: 700, padding: '4px 10px', borderRadius: 20, background: order.status === 'delivered' ? '#dcfce7' : order.status === 'pending' ? '#fef3c7' : '#f3f4f6', color: order.status === 'delivered' ? '#166534' : order.status === 'pending' ? '#92400e' : '#374151' }}>
                          {order.status.toUpperCase()}
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          {/* Status Breakdown */}
          <div className="card" style={{ padding: 24 }}>
            <h2 style={{ fontSize: 18, fontWeight: 700, marginBottom: 24 }}>Order Status</h2>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 20 }}>
              {[
                { label: 'Pending', count: stats?.statusCounts.pending || 0, icon: Clock, color: '#f59e0b' },
                { label: 'Confirmed', count: stats?.statusCounts.confirmed || 0, icon: CheckCircle, color: '#0ea5e9' },
                { label: 'Shipped', count: stats?.statusCounts.shipped || 0, icon: Truck, color: '#8b5cf6' },
                { label: 'Delivered', count: stats?.statusCounts.delivered || 0, icon: CheckCircle, color: '#10b981' },
                { label: 'Cancelled', count: stats?.statusCounts.cancelled || 0, icon: AlertCircle, color: '#ef4444' },
              ].map(item => {
                const percentage = stats?.totalOrders ? (item.count / stats.totalOrders) * 100 : 0
                return (
                  <div key={item.label}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                        <item.icon size={16} color={item.color} />
                        <span style={{ fontSize: 14, fontWeight: 600 }}>{item.label}</span>
                      </div>
                      <span style={{ fontSize: 14, fontWeight: 700 }}>{item.count}</span>
                    </div>
                    <div style={{ height: 8, background: '#f1f5f9', borderRadius: 4, overflow: 'hidden' }}>
                      <div style={{ height: '100%', background: item.color, width: `${percentage}%`, borderRadius: 4 }} />
                    </div>
                  </div>
                )
              })}
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}

'use client'

import { useEffect, useState } from 'react'
import { useAuth } from '@/lib/auth-context'
import { supabase } from '@/lib/supabase'
import AdminSidebar from '@/components/admin/AdminSidebar'
import { Plus, Edit, Trash2, Search, Loader2, X, Image as ImageIcon } from 'lucide-react'
import { toast } from '@/lib/toast'

interface Product {
  id: string; name: string; slug: string; description?: string; price: number; 
  compare_price?: number | null; category_id?: string | null; stock: number;
  sizes?: string[]; colors?: string[]; tags?: string[];
  is_active: boolean; is_featured: boolean; is_best_seller: boolean;
  images: string[]; categories?: { name: string }[] | null; created_at: string
}
interface Category { id: string; name: string }
interface FormData {
  name: string; slug: string; description: string; price: string; compare_price: string;
  category_id: string; stock: string; sizes: string; colors: string; tags: string;
  images: string; is_featured: boolean; is_best_seller: boolean; is_active: boolean
}

const EMPTY_FORM: FormData = {
  name: '', slug: '', description: '', price: '', compare_price: '',
  category_id: '', stock: '0', sizes: 'XS,S,M,L,XL,XXL', colors: '', tags: '',
  images: '', is_featured: false, is_best_seller: false, is_active: true
}

export default function AdminProductsPage() {
  const { profile, loading } = useAuth()
  const [products, setProducts] = useState<Product[]>([])
  const [categories, setCategories] = useState<Category[]>([])
  const [search, setSearch] = useState('')
  const [modalOpen, setModalOpen] = useState(false)
  const [editingId, setEditingId] = useState<string | null>(null)
  const [form, setForm] = useState<FormData>(EMPTY_FORM)
  const [saving, setSaving] = useState(false)
  const [fetching, setFetching] = useState(true)
  const [uploading, setUploading] = useState(false)

  useEffect(() => { if (profile?.is_admin) fetchData() }, [profile])

  async function fetchData() {
    setFetching(true)
    const [pRes, cRes] = await Promise.all([
      supabase.from('products').select('id,name,slug,description,price,compare_price,category_id,stock,sizes,colors,tags,is_active,is_featured,is_best_seller,images,categories(name),created_at').order('created_at', { ascending: false }),
      supabase.from('categories').select('id,name').eq('is_active', true).order('sort_order')
    ])
    setProducts(pRes.data || [])
    setCategories(cRes.data || [])
    setFetching(false)
  }

  const openCreate = () => { setForm(EMPTY_FORM); setEditingId(null); setModalOpen(true) }
  const openEdit = (p: Product) => {
    setForm({
      name: p.name, slug: p.slug, description: p.description || '', price: String(p.price),
      compare_price: p.compare_price ? String(p.compare_price) : '', category_id: p.category_id || '', stock: String(p.stock),
      sizes: (p.sizes || []).join(','), colors: (p.colors || []).join(','), tags: (p.tags || []).join(','),
      images: (p.images || []).join('\n'), is_featured: p.is_featured,
      is_best_seller: p.is_best_seller, is_active: p.is_active
    })
    setEditingId(p.id)
    setModalOpen(true)
  }

  const handleUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    try {
      const files = Array.from(e.target.files || [])
      if (files.length === 0) return

      setUploading(true)
      const newImages: string[] = []

      for (const file of files) {
        const fileExt = file.name.split('.').pop()
        const fileName = `${Math.random()}.${fileExt}`
        const filePath = `products/${fileName}`

        const { error: uploadError } = await supabase.storage
          .from('products')
          .upload(filePath, file)

        if (uploadError) throw uploadError

        const { data: { publicUrl } } = supabase.storage
          .from('products')
          .getPublicUrl(filePath)

        newImages.push(publicUrl)
      }

      const currentImages = form.images.split('\n').filter(Boolean)
      setForm({ ...form, images: [...currentImages, ...newImages].join('\n') })
      toast.success(`${files.length} images uploaded`)
    } catch (error: any) {
      toast.error(error.message || 'Error uploading')
    } finally {
      setUploading(false)
    }
  }

  const handleSave = async () => {
    if (!form.name.trim() || !form.price) { toast.error('Name and price are required'); return }
    setSaving(true)

    const slug = form.slug || form.name.toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '')
    const payload = {
      name: form.name.trim(),
      slug,
      description: form.description,
      price: parseFloat(form.price),
      compare_price: form.compare_price ? parseFloat(form.compare_price) : null,
      category_id: form.category_id || null,
      stock: parseInt(form.stock) || 0,
      sizes: form.sizes.split(',').map(s => s.trim()).filter(Boolean),
      colors: form.colors.split(',').map(s => s.trim()).filter(Boolean),
      tags: form.tags.split(',').map(s => s.trim()).filter(Boolean),
      images: form.images.split('\n').map(s => s.trim()).filter(Boolean),
      is_featured: form.is_featured,
      is_best_seller: form.is_best_seller,
      is_active: form.is_active
    }

    if (editingId) {
      const { error } = await supabase.from('products').update(payload).eq('id', editingId)
      if (error) toast.error(error.message)
      else { toast.success('Product updated!'); setModalOpen(false); fetchData() }
    } else {
      const { error } = await supabase.from('products').insert(payload)
      if (error) toast.error(error.message)
      else { toast.success('Product created!'); setModalOpen(false); fetchData() }
    }
    setSaving(false)
  }

  const handleDelete = async (id: string, name: string) => {
    if (!confirm(`Delete "${name}"? This cannot be undone.`)) return
    const { error } = await supabase.from('products').delete().eq('id', id)
    if (error) toast.error(error.message)
    else { toast.success('Product deleted'); fetchData() }
  }

  const filtered = products.filter(p => p.name.toLowerCase().includes(search.toLowerCase()))

  if (!profile?.is_admin) return null

  return (
    <div style={{ display: 'flex', minHeight: '100vh', background: 'var(--bg-primary)' }}>
      <AdminSidebar active="products" />

      <div style={{ flex: 1, padding: 32, overflow: 'auto' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 32 }}>
          <h1 style={{ fontFamily: 'var(--font-heading)', fontSize: 28, fontWeight: 800 }}>Products</h1>
          <button onClick={openCreate} className="btn btn-primary">
            <Plus size={16} /> Add Product
          </button>
        </div>

        {/* Search */}
        <div style={{ position: 'relative', marginBottom: 24, maxWidth: 400 }}>
          <Search size={16} style={{ position: 'absolute', left: 14, top: '50%', transform: 'translateY(-50%)', color: 'var(--text-muted)' }} />
          <input
            value={search} onChange={e => setSearch(e.target.value)}
            className="form-input" placeholder="Search products..."
            style={{ paddingLeft: 40 }}
          />
        </div>

        {/* Table */}
        <div className="card" style={{ overflow: 'hidden', padding: 0 }}>
          {fetching ? (
            <div style={{ padding: 40, textAlign: 'center' }}><Loader2 size={24} style={{ animation: 'spin 1s linear infinite', color: 'var(--gold)' }} /></div>
          ) : (
            <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 14 }}>
              <thead>
                <tr style={{ background: 'var(--bg-primary)' }}>
                  {['Product', 'Category', 'Price', 'Stock', 'Status', 'Actions'].map(h => (
                    <th key={h} style={{ padding: '10px 16px', textAlign: 'left', fontSize: 11, fontWeight: 700, letterSpacing: '0.08em', textTransform: 'uppercase', color: 'var(--text-muted)' }}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {filtered.map(product => (
                  <tr key={product.id} style={{ borderTop: '1px solid var(--border)' }}>
                    <td style={{ padding: '12px 16px' }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                        <div style={{ width: 44, height: 52, borderRadius: 6, background: '#f0ece6', overflow: 'hidden', flexShrink: 0 }}>
                          {product.images?.[0] ? <img src={product.images[0]} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} /> : <ImageIcon size={18} color="var(--text-muted)" style={{ margin: '17px auto', display: 'block' }} />}
                        </div>
                        <div>
                          <div style={{ fontWeight: 600, color: 'var(--dark)', marginBottom: 2 }}>{product.name}</div>
                          <div style={{ fontSize: 11, color: 'var(--text-muted)' }}>{product.slug}</div>
                        </div>
                      </div>
                    </td>
                    <td style={{ padding: '12px 16px', color: 'var(--text-secondary)' }}>{product.categories?.[0]?.name || '—'}</td>
                    <td style={{ padding: '12px 16px', fontWeight: 600 }}>Rs. {product.price.toLocaleString()}</td>
                    <td style={{ padding: '12px 16px' }}>
                      <span style={{ color: product.stock === 0 ? '#ef4444' : product.stock < 5 ? '#f59e0b' : '#22c55e', fontWeight: 600 }}>{product.stock}</span>
                    </td>
                    <td style={{ padding: '12px 16px' }}>
                      <div style={{ display: 'flex', gap: 4, flexWrap: 'wrap' }}>
                        {product.is_active && <span className="badge" style={{ background: '#d1fae5', color: '#065f46', fontSize: 10 }}>Active</span>}
                        {product.is_featured && <span className="badge" style={{ background: '#dbeafe', color: '#1e40af', fontSize: 10 }}>Featured</span>}
                        {product.is_best_seller && <span className="badge" style={{ background: '#fef3c7', color: '#92400e', fontSize: 10 }}>Best Seller</span>}
                        {!product.is_active && <span className="badge" style={{ background: '#fee2e2', color: '#991b1b', fontSize: 10 }}>Inactive</span>}
                      </div>
                    </td>
                    <td style={{ padding: '12px 16px' }}>
                      <div style={{ display: 'flex', gap: 8 }}>
                        <button onClick={() => openEdit(product)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--gold)', display: 'flex', padding: 6 }}><Edit size={16} /></button>
                        <button onClick={() => handleDelete(product.id, product.name)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#ef4444', display: 'flex', padding: 6 }}><Trash2 size={16} /></button>
                      </div>
                    </td>
                  </tr>
                ))}
                {filtered.length === 0 && (
                  <tr><td colSpan={6} style={{ padding: 40, textAlign: 'center', color: 'var(--text-muted)' }}>No products found</td></tr>
                )}
              </tbody>
            </table>
          )}
        </div>
      </div>

      {/* Modal */}
      {modalOpen && (
        <div style={{ position: 'fixed', inset: 0, zIndex: 400, background: 'rgba(0,0,0,0.6)', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 16 }}>
          <div style={{ background: '#fff', borderRadius: 16, padding: 32, width: '100%', maxWidth: 680, maxHeight: '90vh', overflowY: 'auto', position: 'relative' }}>
