              <button onClick={() => setModalOpen(false)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-muted)' }}><X size={20} /></button>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
              <div className="form-group" style={{ gridColumn: '1/-1' }}>
                <label className="form-label">Product Name *</label>
                <input className="form-input" value={form.name} onChange={e => {
                  const name = e.target.value
                  setForm(f => ({ ...f, name, slug: name.toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '') }))
                }} placeholder="Premium Cotton T-Shirt" />
              </div>
              <div className="form-group">
                <label className="form-label">Price (Rs.) *</label>
                <input className="form-input" type="number" value={form.price} onChange={e => setForm(f => ({ ...f, price: e.target.value }))} placeholder="1500" />
              </div>
              <div className="form-group">
                <label className="form-label">Compare Price (Rs.)</label>
                <input className="form-input" type="number" value={form.compare_price} onChange={e => setForm(f => ({ ...f, compare_price: e.target.value }))} placeholder="2000" />
              </div>
              <div className="form-group">
                <label className="form-label">Category</label>
                <select className="form-input" value={form.category_id} onChange={e => setForm(f => ({ ...f, category_id: e.target.value }))}>
                  <option value="">Select category...</option>
                  {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                </select>
              </div>
              <div className="form-group">
                <label className="form-label">Stock</label>
                <input className="form-input" type="number" value={form.stock} onChange={e => setForm(f => ({ ...f, stock: e.target.value }))} />
              </div>
              <div className="form-group">
                <label className="form-label">Sizes (comma-separated)</label>
                <input className="form-input" value={form.sizes} onChange={e => setForm(f => ({ ...f, sizes: e.target.value }))} placeholder="XS,S,M,L,XL" />
              </div>
              <div className="form-group">
                <label className="form-label">Colors (comma-separated)</label>
                <input className="form-input" value={form.colors} onChange={e => setForm(f => ({ ...f, colors: e.target.value }))} placeholder="Black,White,Navy" />
              </div>
              <div className="form-group" style={{ gridColumn: '1/-1' }}>
                <label className="form-label">Description</label>
                <textarea className="form-input" value={form.description} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} rows={3} style={{ resize: 'vertical' }} placeholder="Product description..." />
              </div>
              <div className="form-group" style={{ gridColumn: '1/-1' }}>
                <label className="form-label" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  Images
                  <label className="text-gold" style={{ cursor: 'pointer', fontSize: 12, fontWeight: 600, display: 'flex', alignItems: 'center', gap: 4 }}>
                    <Plus size={14} /> {uploading ? 'Uploading...' : 'Upload from Device'}
                    <input type="file" multiple accept="image/*" onChange={handleUpload} disabled={uploading} style={{ display: 'none' }} />
                  </label>
                </label>
                <textarea 
                  className="form-input" 
                  value={form.images} 
                  onChange={e => setForm(f => ({ ...f, images: e.target.value }))} 
                  rows={4} 
                  style={{ resize: 'vertical' }} 
                  placeholder="Image URLs (one per line)&#10;Or use the upload button above" 
                />
                {form.images && (
                  <div style={{ display: 'flex', gap: 8, marginTop: 12, overflowX: 'auto', paddingBottom: 8 }}>
                    {form.images.split('\n').filter(Boolean).map((url, i) => (
                      <div key={i} style={{ position: 'relative', width: 60, height: 60, borderRadius: 8, overflow: 'hidden', flexShrink: 0, border: '1px solid var(--border)' }}>
                        <img src={url} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                        <button 
                          onClick={() => {
                            const imgs = form.images.split('\n').filter((_, idx) => idx !== i)
                            setForm({ ...form, images: imgs.join('\n') })
                          }}
                          style={{ position: 'absolute', top: 2, right: 2, background: 'rgba(255,255,255,0.8)', border: 'none', borderRadius: '50%', width: 16, height: 16, display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', color: '#ef4444' }}
                        >
                          <X size={10} />
                        </button>
                      </div>
                    ))}
                  </div>
                )}
              </div>
              <div className="form-group">
                <label className="form-label">Tags (comma-separated)</label>
                <input className="form-input" value={form.tags} onChange={e => setForm(f => ({ ...f, tags: e.target.value }))} placeholder="cotton, premium, summer" />
              </div>
              <div className="form-group">
                <label className="form-label">Slug (auto-generated)</label>
                <input className="form-input" value={form.slug} onChange={e => setForm(f => ({ ...f, slug: e.target.value }))} />
              </div>
            </div>

            <div style={{ display: 'flex', gap: 20, marginTop: 16 }}>
              {[
                { key: 'is_active', label: 'Active' },
                { key: 'is_featured', label: 'Featured' },
                { key: 'is_best_seller', label: 'Best Seller' }
              ].map(({ key, label }) => (
                <label key={key} style={{ display: 'flex', alignItems: 'center', gap: 8, cursor: 'pointer', fontSize: 14 }}>
                  <input type="checkbox" checked={form[key as keyof FormData] as boolean} onChange={e => setForm(f => ({ ...f, [key]: e.target.checked }))} />
                  {label}
                </label>
              ))}
            </div>

            <div style={{ display: 'flex', gap: 12, marginTop: 24, justifyContent: 'flex-end' }}>
              <button onClick={() => setModalOpen(false)} className="btn btn-outline">Cancel</button>
              <button onClick={handleSave} className="btn btn-primary" disabled={saving}>
                {saving ? <Loader2 size={16} style={{ animation: 'spin 1s linear infinite' }} /> : editingId ? 'Update Product' : 'Create Product'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

'use client'

import { useEffect, useState, Suspense } from 'react'
import { useSearchParams } from 'next/navigation'
import { supabase } from '@/lib/supabase'
import ProductCard, { ProductCardSkeleton } from '@/components/ui/ProductCard'
import { SlidersHorizontal, X, ChevronDown } from 'lucide-react'

interface Product {
  id: string; name: string; slug: string; price: number;
  compare_price?: number | null; images: string[];
  is_best_seller?: boolean; is_featured?: boolean
}
interface Category { id: string; name: string; slug: string }

const PRICE_RANGES = [
  { label: 'Under Rs. 1,000', min: 0, max: 1000 },
  { label: 'Rs. 1,000 – 2,500', min: 1000, max: 2500 },
  { label: 'Rs. 2,500 – 5,000', min: 2500, max: 5000 },
  { label: 'Above Rs. 5,000', min: 5000, max: 999999 },
]

const SORT_OPTIONS = [
  { label: 'Newest', value: 'created_at:desc' },
  { label: 'Price: Low to High', value: 'price:asc' },
  { label: 'Price: High to Low', value: 'price:desc' },
  { label: 'Best Sellers', value: 'best_seller' },
]

function CategoriesContent() {
  const searchParams = useSearchParams()
  const catSlug = searchParams.get('cat')
  const colSlug = searchParams.get('col')
  const sortParam = searchParams.get('sort')
  const featuredParam = searchParams.get('featured')
  const queryParam = searchParams.get('q')

  const [products, setProducts] = useState<Product[]>([])
  const [categories, setCategories] = useState<Category[]>([])
  const [collections, setCollections] = useState<{id: string, title: string, slug: string}[]>([])
  const [loading, setLoading] = useState(true)
  const [activeCategory, setActiveCategory] = useState(catSlug || '')
  const [activeCollection, setActiveCollection] = useState(colSlug || '')
  const [activePriceRange, setActivePriceRange] = useState<typeof PRICE_RANGES[0] | null>(null)
  const [sort, setSort] = useState(sortParam === 'best_seller' ? 'best_seller' : 'created_at:desc')
  const [filterOpen, setFilterOpen] = useState(false)
  const [page, setPage] = useState(0)
  const PAGE_SIZE = 20

  useEffect(() => {
    supabase.from('categories').select('id,name,slug').eq('is_active', true).order('sort_order').then(({ data }) => setCategories(data || []))
    supabase.from('collections').select('id,title,slug').eq('is_active', true).then(({ data }) => setCollections(data || []))
  }, [])

  useEffect(() => {
    setLoading(true)
    setPage(0)
    fetchProducts()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [activeCategory, activeCollection, activePriceRange, sort, queryParam, featuredParam])

  async function fetchProducts() {
    let query = supabase.from('products').select('id,name,slug,price,compare_price,images,is_featured,is_best_seller', { count: 'exact' }).eq('is_active', true)
    if (activeCategory) {
      const cat = categories.find(c => c.slug === activeCategory)
      if (cat) query = query.eq('category_id', cat.id)
    }
    if (activeCollection) {
      const col = collections.find(c => c.slug === activeCollection)
      if (col) query = query.eq('collection_id', col.id)
    }
    if (activePriceRange) query = query.gte('price', activePriceRange.min).lte('price', activePriceRange.max)
    if (featuredParam === 'true') query = query.eq('is_featured', true)
    if (sort === 'best_seller') query = query.eq('is_best_seller', true)
    if (queryParam) query = query.ilike('name', `%${queryParam}%`)
    if (sort !== 'best_seller') {
      const [col, dir] = sort.split(':')
      query = query.order(col, { ascending: dir === 'asc' })
    } else {
      query = query.order('created_at', { ascending: false })
    }
    query = query.range(0, PAGE_SIZE - 1)
    const { data } = await query
    setProducts(data || [])
    setLoading(false)
  }

  const clearFilters = () => {
    setActiveCategory('')
    setActiveCollection('')
    setActivePriceRange(null)
    setSort('created_at:desc')
  }

  const hasFilters = activeCategory || activeCollection || activePriceRange

  return (
    <div className="page-enter">
      {/* Header */}
      <div style={{ background: 'var(--dark)', padding: 'clamp(32px, 5vw, 56px) 0' }}>
        <div className="container">
          <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: '0.2em', textTransform: 'uppercase', color: 'var(--gold)', marginBottom: 8 }}>
            {activeCategory ? categories.find(c => c.slug === activeCategory)?.name : activeCollection ? 'Collection' : 'All Products'}
          </div>
          <h1 style={{ color: '#fff', fontFamily: 'var(--font-heading)', fontSize: 'clamp(28px, 4vw, 48px)', fontWeight: 800, letterSpacing: '-0.02em' }}>
            {queryParam ? `Search: "${queryParam}"` : activeCategory ? categories.find(c => c.slug === activeCategory)?.name : activeCollection ? collections.find(c => c.slug === activeCollection)?.title : 'Shop All'}
          </h1>
        </div>
      </div>

      <div className="container section">
        {/* Toolbar */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 32, flexWrap: 'wrap', gap: 12 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <button onClick={() => setFilterOpen(!filterOpen)} className="btn btn-outline btn-sm" style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
              <SlidersHorizontal size={16} /> Filters {hasFilters && <span style={{ background: 'var(--gold)', color: '#fff', borderRadius: '50%', width: 16, height: 16, fontSize: 10, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>!</span>}
            </button>
            {hasFilters && (
              <button onClick={clearFilters} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-muted)', fontSize: 13, display: 'flex', alignItems: 'center', gap: 4 }}>
                <X size={14} /> Clear
              </button>
            )}
            <span style={{ fontSize: 13, color: 'var(--text-muted)' }}>{products.length} products</span>
          </div>

          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <span style={{ fontSize: 13, color: 'var(--text-muted)' }}>Sort by:</span>
            <div style={{ position: 'relative' }}>
              <select
                value={sort}
                onChange={e => setSort(e.target.value)}
                style={{ padding: '8px 32px 8px 12px', border: '1.5px solid var(--border)', borderRadius: 6, fontSize: 13, fontFamily: 'var(--font-body)', cursor: 'pointer', appearance: 'none', background: '#fff', color: 'var(--text-primary)', outline: 'none' }}
              >
                {SORT_OPTIONS.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}
              </select>
              <ChevronDown size={14} style={{ position: 'absolute', right: 10, top: '50%', transform: 'translateY(-50%)', pointerEvents: 'none', color: 'var(--text-muted)' }} />
            </div>
          </div>
        </div>

        <div style={{ display: 'flex', gap: 24, alignItems: 'flex-start' }}>
          {/* Filter Sidebar */}
          {filterOpen && (
            <div className="filter-sidebar" style={{ minWidth: 220, width: 220 }}>
              <div style={{ fontSize: 13, fontWeight: 700, letterSpacing: '0.08em', textTransform: 'uppercase', color: 'var(--text-secondary)', marginBottom: 20 }}>Categories</div>
              {categories.map(cat => (
                <button key={cat.id} onClick={() => setActiveCategory(activeCategory === cat.slug ? '' : cat.slug)} style={{
                  display: 'block', width: '100%', textAlign: 'left', padding: '9px 12px',
                  background: activeCategory === cat.slug ? 'var(--dark)' : 'transparent',
                  color: activeCategory === cat.slug ? '#fff' : 'var(--text-primary)',
                  border: 'none', borderRadius: 6, fontSize: 14, cursor: 'pointer',
                  fontWeight: activeCategory === cat.slug ? 600 : 400, transition: 'all 0.2s',
                  marginBottom: 2
                }}>
                  {cat.name}
                </button>
              ))}

              <div style={{ borderTop: '1px solid var(--border)', marginTop: 20, paddingTop: 20, fontSize: 13, fontWeight: 700, letterSpacing: '0.08em', textTransform: 'uppercase', color: 'var(--text-secondary)', marginBottom: 20 }}>Price Range</div>
              {PRICE_RANGES.map(range => (
                <button key={range.label} onClick={() => setActivePriceRange(activePriceRange?.label === range.label ? null : range)} style={{
                  display: 'block', width: '100%', textAlign: 'left', padding: '9px 12px',
                  background: activePriceRange?.label === range.label ? 'var(--dark)' : 'transparent',
                  color: activePriceRange?.label === range.label ? '#fff' : 'var(--text-primary)',
                  border: 'none', borderRadius: 6, fontSize: 14, cursor: 'pointer', transition: 'all 0.2s', marginBottom: 2
                }}>
                  {range.label}
                </button>
              ))}
            </div>
          )}

          {/* Product Grid */}
          <div style={{ flex: 1 }}>
            <div className="product-grid">
              {loading
                ? Array(8).fill(0).map((_, i) => <ProductCardSkeleton key={i} />)
                : products.length > 0
                  ? products.map(p => <ProductCard key={p.id} product={p} />)
                  : (
                    <div style={{ gridColumn: '1/-1', textAlign: 'center', padding: '80px 0', color: 'var(--text-muted)' }}>
                      <div style={{ fontSize: 48, marginBottom: 16 }}>🔍</div>
                      <h3 style={{ fontFamily: 'var(--font-heading)', marginBottom: 8 }}>No products found</h3>
                      <p>Try changing your filters or search term</p>
                      <button onClick={clearFilters} className="btn btn-primary" style={{ marginTop: 20 }}>Clear Filters</button>
                    </div>
                  )
              }
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}

export default function CategoriesPage() {
  return <Suspense fallback={<div className="container section"><div className="product-grid">{Array(8).fill(0).map((_, i) => <ProductCardSkeleton key={i} />)}</div></div>}>
    <CategoriesContent />
  </Suspense>
}

'use client'

import { useState, useEffect } from 'react'
import { useAuth } from '@/lib/auth-context'
import { supabase } from '@/lib/supabase'
import { toast } from '@/lib/toast'
import { User, Package, MapPin, LogOut, Lock, Edit3, Loader2 } from 'lucide-react'
import Link from 'next/link'
import { useRouter } from 'next/navigation'

interface Order {
  id: string; order_number: string; status: string; total: number; created_at: string; items: unknown[]
}

type Tab = 'profile' | 'orders' | 'addresses' | 'password'

export default function ProfilePage() {
  const { user, profile, signOut, updateProfile, loading } = useAuth()
  const router = useRouter()
  const [activeTab, setActiveTab] = useState<Tab>('profile')
  const [orders, setOrders] = useState<Order[]>([])
  const [ordersLoaded, setOrdersLoaded] = useState(false)
  const [profileForm, setProfileForm] = useState({ full_name: profile?.full_name || '', phone: profile?.phone || '' })
  const [passwordForm, setPasswordForm] = useState({ current: '', new: '', confirm: '' })
  const [saving, setSaving] = useState(false)

  useEffect(() => {
    if (!loading && !user) {
      router.push('/login')
    }
  }, [user, loading, router])

  // Sync profile form when profile loads
  useEffect(() => {
    if (profile) {
      setProfileForm({ 
        full_name: profile.full_name || '', 
        phone: profile.phone || '' 
      })
    }
  }, [profile])

  if (loading || (!user && !loading)) {
    return (
      <div className="container section" style={{ textAlign: 'center' }}>
        <Loader2 size={32} style={{ animation: 'spin 1s linear infinite', color: 'var(--gold)' }} />
      </div>
    )
  }

  const handleTabChange = async (tab: Tab) => {
    setActiveTab(tab)
    if (tab === 'orders' && !ordersLoaded) {
      const { data } = await supabase.from('orders').select('id,order_number,status,total,created_at,items').eq('user_id', user.id).order('created_at', { ascending: false })
      setOrders(data || [])
      setOrdersLoaded(true)
    }
  }

  const handleSaveProfile = async () => {
    setSaving(true)
    const { error } = await updateProfile({ full_name: profileForm.full_name, phone: profileForm.phone })
    setSaving(false)
    if (error) toast.error('Failed to update profile')
    else toast.success('Profile updated!')
  }

  const handleChangePassword = async () => {
    if (passwordForm.new !== passwordForm.confirm) { toast.error('Passwords do not match'); return }
    if (passwordForm.new.length < 6) { toast.error('Password must be at least 6 characters'); return }
    setSaving(true)
    const { error } = await supabase.auth.updateUser({ password: passwordForm.new })
    setSaving(false)
    if (error) toast.error(error.message)
    else { toast.success('Password updated!'); setPasswordForm({ current: '', new: '', confirm: '' }) }
  }

  const handleSignOut = async () => {
    await signOut()
    router.push('/')
    toast.success('Signed out successfully')
  }

  const TAB_ITEMS: { key: Tab; label: string; icon: React.ComponentType<{ size?: number }> }[] = [
    { key: 'profile', label: 'My Profile', icon: User },
    { key: 'orders', label: 'Order History', icon: Package },
    { key: 'addresses', label: 'Addresses', icon: MapPin },
    { key: 'password', label: 'Change Password', icon: Lock },
  ]

  return (
    <div className="page-enter">
      <div style={{ background: 'var(--dark)', padding: 'clamp(24px, 4vw, 40px) 0' }}>
        <div className="container">
          <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
            <div style={{ width: 56, height: 56, borderRadius: '50%', background: 'var(--gold)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 22, fontWeight: 700, color: '#fff', fontFamily: 'var(--font-heading)' }}>
              {profile?.full_name?.[0] || user.email?.[0]?.toUpperCase() || 'U'}
            </div>
            <div>
              <h1 style={{ color: '#fff', fontFamily: 'var(--font-heading)', fontSize: 22, fontWeight: 700 }}>{profile?.full_name || 'My Account'}</h1>
              <p style={{ color: 'rgba(255,255,255,0.5)', fontSize: 14 }}>{user.email}</p>
            </div>
          </div>
        </div>
      </div>

      <div className="container" style={{ paddingTop: 40, paddingBottom: 80 }}>
        <div style={{ display: 'grid', gridTemplateColumns: '220px 1fr', gap: 32, alignItems: 'start' }}>

          {/* Sidebar */}
          <div className="card" style={{ padding: 8 }}>
            {TAB_ITEMS.map(item => {
              const Icon = item.icon
              return (
                <button key={item.key} onClick={() => handleTabChange(item.key)} style={{
                  display: 'flex', alignItems: 'center', gap: 10, width: '100%', padding: '12px 16px',
                  background: activeTab === item.key ? 'var(--dark)' : 'none',
                  color: activeTab === item.key ? '#fff' : 'var(--text-secondary)',
                  border: 'none', borderRadius: 6, fontSize: 14, fontWeight: 500,
                  cursor: 'pointer', transition: 'all 0.2s', textAlign: 'left', marginBottom: 2
                }}>
                  <Icon size={16} /> {item.label}
                </button>
              )
            })}
            <div style={{ borderTop: '1px solid var(--border)', marginTop: 8, paddingTop: 8 }}>
              <button onClick={handleSignOut} style={{ display: 'flex', alignItems: 'center', gap: 10, width: '100%', padding: '12px 16px', background: 'none', color: '#ef4444', border: 'none', borderRadius: 6, fontSize: 14, fontWeight: 500, cursor: 'pointer', transition: 'all 0.2s', textAlign: 'left' }}>
                <LogOut size={16} /> Sign Out
              </button>
            </div>
          </div>

          {/* Content */}
          <div className="card" style={{ padding: 32 }}>
            {activeTab === 'profile' && (
              <div>
                <h2 className="heading-md" style={{ marginBottom: 24 }}>
                  <Edit3 size={20} style={{ display: 'inline', marginRight: 8, verticalAlign: 'middle' }} />
                  Edit Profile
                </h2>
                <div style={{ display: 'flex', flexDirection: 'column', gap: 16, maxWidth: 480 }}>
                  <div className="form-group">
                    <label className="form-label">Full Name</label>
                    <input className="form-input" id="profile-name" value={profileForm.full_name} onChange={e => setProfileForm(f => ({ ...f, full_name: e.target.value }))} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Phone Number</label>
                    <input className="form-input" id="profile-phone" value={profileForm.phone} onChange={e => setProfileForm(f => ({ ...f, phone: e.target.value }))} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Email</label>
                    <input className="form-input" value={user.email || ''} disabled style={{ opacity: 0.6, cursor: 'not-allowed' }} />
                  </div>
                  <button onClick={handleSaveProfile} className="btn btn-primary" disabled={saving} style={{ width: 'fit-content' }}>
                    {saving ? <Loader2 size={16} style={{ animation: 'spin 1s linear infinite' }} /> : 'Save Changes'}
                  </button>
                </div>
              </div>
            )}

            {activeTab === 'orders' && (
              <div>
                <h2 className="heading-md" style={{ marginBottom: 24 }}>Order History</h2>
                {orders.length === 0 ? (
                  <div style={{ textAlign: 'center', padding: '40px 0', color: 'var(--text-muted)' }}>
                    <Package size={48} style={{ marginBottom: 16, opacity: 0.3 }} />
                    <p>No orders yet</p>
