function NavLink({ href, label, active }: { href: string; label: string; active: boolean }) {
  return (
    <Link href={href} style={{
      padding: '8px 14px', fontSize: 14, fontWeight: active ? 600 : 500,
      color: active ? 'var(--gold)' : 'var(--text-primary)',
      textDecoration: 'none', borderRadius: 4, transition: 'color 0.2s',
      letterSpacing: '0.02em'
    }}>
      {label}
    </Link>
  )
}

function MobileNavLink({ href, label, small }: { href: string; label: string; small?: boolean }) {
  return (
    <Link href={href} style={{
      display: 'block', padding: small ? '9px 12px' : '12px 0',
      fontSize: small ? 14 : 16, fontWeight: 500,
      color: 'var(--text-primary)', textDecoration: 'none',
      borderRadius: small ? 4 : 0, transition: 'color 0.2s'
    }}>
      {label}
    </Link>
  )
}

'use client'

import { useEffect, useState } from 'react'
import { motion, AnimatePresence } from 'framer-motion'

export default function SplashScreen() {
  const [show, setShow] = useState(true)

  useEffect(() => {
    const seen = sessionStorage.getItem('ag-splash-seen')
    if (seen) { setShow(false); return }
    const timer = setTimeout(() => {
      setShow(false)
      sessionStorage.setItem('ag-splash-seen', '1')
    }, 2800)
    return () => clearTimeout(timer)
  }, [])

  return (
    <AnimatePresence>
      {show && (
        <motion.div
          initial={{ opacity: 1 }}
          exit={{ opacity: 0, transition: { duration: 0.6, ease: 'easeInOut' } }}
          style={{
            position: 'fixed', inset: 0, zIndex: 9999,
            background: '#111111',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            flexDirection: 'column', gap: 24
          }}
        >
          {/* Logo */}
          <motion.div
            initial={{ opacity: 0, y: 30 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.8, ease: [0.4, 0, 0.2, 1] }}
            style={{ textAlign: 'center' }}
          >
            <motion.div
              initial={{ scaleX: 0 }}
              animate={{ scaleX: 1 }}
              transition={{ delay: 0.4, duration: 0.6, ease: 'easeOut' }}
              style={{
                height: 2, background: '#C9A66B',
                marginBottom: 20, transformOrigin: 'left'
              }}
            />
            <h1 style={{
              fontFamily: "'Poppins', sans-serif",
              fontSize: 'clamp(28px, 5vw, 48px)',
              fontWeight: 300,
              color: '#fff',
              letterSpacing: '0.3em',
              textTransform: 'uppercase',
              lineHeight: 1.1
            }}>
              Aurangzaib
            </h1>
            <motion.h2
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
